3_real_world_example.code:
//  Return — produces a value that can be used further
function calcTotal(price, qty) {
  return price * qty; // exits here with the result
  console.log('This never runs'); // unreachable code!
}

function formatPrice(amount) {
  return `$${amount.toFixed(2)}`;
}

// Compose the two functions
const display = formatPrice(calcTotal(9.99, 3));
console.log(display); // '$29.97'

//  Anti-pattern — using console.log instead of return
function badCalc(price, qty) {
  console.log(price * qty); // prints but returns nothing useful
}
const bad = badCalc(9.99, 3); // bad === undefined

6_edge_case.code:
function getData() {
  return   // ️ ASI inserts ';' here — returns undefined!
  {
    name: 'SkillSprint'
  };
}

console.log(getData()); // undefined — not the object!

//  Fix: keep the opening brace on the same line as return
function getDataFixed() {
  return {   // no line break before the value
    name: 'SkillSprint'
  };
}
console.log(getDataFixed()); // { name: 'SkillSprint' }
